情況 2 之下，X1 年度「透過其他綜合損益按公允價值衡量之債務
工具處分（損）益」？X1 年 12 月 31 日「其他權益－透過其他綜
合損益按公允價值衡量之債務工具投資評價損益」餘額？（10分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:07+00:00", "source_pdf_sha1": "79dbd7193b47", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "314", "s": "1710", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "中級會計學", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00210', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-112-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '甲公司 X3 年的綜合損益表包含下列項目：出售透過其他綜合損益按公允價值衡量之債務工 具投資利益$15,000、國外營運機構財務報表換算之兌換差額$2,600，確定福利計畫下之再衡 量損失$8,400，地震災損$3,000，公允價值模式下之投資性不動產公允價值調整利益$6,600。 假設上述金額均為稅後，且無其他收益費損項目，試問甲公司X3年之本期淨利金額為何？', '["$7,600", "$10,200", "$16,000", "$18,600"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:07+00:00", "source_pdf_sha1": "79dbd7193b47", "answer_pdf_sha1": "2817fe9caeb5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "314", "s": "1710", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00211', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-112-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '甲公司於X2年初以$525,000買入乙公司發行之可轉換公司債，面額為$500,000，另支付手續 費$2,350。購買當日公司債轉換權之公允價值為$13,200，試問購買時應作之分錄包含：', '["借：透過損益按公允價值衡量之債券投資$514,091", "借：透過損益按公允價值衡量之債券投資$525,000", "借：透過損益按公允價值衡量之金融資產－轉換權$13,141", "借：透過損益按公允價值衡量之金融資產－轉換權$13,200"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:07+00:00", "source_pdf_sha1": "79dbd7193b47", "answer_pdf_sha1": "2817fe9caeb5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "314", "s": "1710", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00212', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-112-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '下列有關會計政策及會計估計變動之敘述何者錯誤？', '["若會計估計變動及會計政策變動同時發生且二者影響可劃分時，應先處理會計政策變動， 再計算估計變動之影響", "若一項會計變動無法明顯區分是會計政策變動，或是會計估計變動時，該變動應視為會計 估計變動", "應收帳款壞帳衡量方式由帳齡分析法改為應收帳款餘額百分比法為會計政策變動", "交易、其他事項或情況之實質不同於先前發生者，所採用之會計政策非屬會計政策變動"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:07+00:00", "source_pdf_sha1": "79dbd7193b47", "answer_pdf_sha1": "2817fe9caeb5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "314", "s": "1710", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00213', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-112-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '甲公司於X1年1月1日以$180,000購入設備，估計耐用年限5年，無殘值。會計帳上使用 年數合計法提列折舊，報稅時使用直線法。X1年底時外幣應收帳款按期末匯率衡量，認列外 幣兌換損失$21,000，依稅法規定實現時方可認列。假設甲公司X1年的會計利潤為$490,000， 稅率為20%，且無發生其他造成會計利潤與課稅所得間差異的交易。試問X1年底與所得稅 有關的敘述何者正確？', '["遞延所得稅資產$9,000", "應付所得稅$102,800", "所得稅費用$116,000", "遞延所得稅資產$600"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:07+00:00", "source_pdf_sha1": "79dbd7193b47", "answer_pdf_sha1": "2817fe9caeb5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "314", "s": "1710", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL)
